func calendarDayHeading(month, day int) string {
	if day <= 0 {
		return monthName(month) + " (unknown day)"
	}
	return fmt.Sprintf("%s %d", monthName(month), day)
}

func calendarItemTypeLabel(itemType string) string {
	switch itemType {
	case "holiday":
		return "Holiday"
	default:
		return "Event"
	}
}

func calendarItemBadgeClass(itemType string) string {
	switch itemType {
	case "holiday":
		return "inline-flex rounded-full border border-[#7d2a2a] bg-[#d98989] px-2 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-[#401717]"
	default:
		return "inline-flex rounded-full border border-[#265c8a] bg-[#7cb3e2] px-2 py-1 text-xs font-semibold uppercase tracking-[0.18em] text-[#18324a]"
	}
}

func calendarDayStatusClass(kind string) string {
	base := "rounded-2xl border px-4 py-3 text-sm"
	if kind == "success" {
		return base + " border-[rgba(38,101,66,0.28)] bg-[rgba(38,101,66,0.09)] text-[#1f5b3b]"
	}
	return base + " border-[rgba(111,44,38,0.28)] bg-[rgba(111,44,38,0.08)] text-[#6f2c26]"
}

